-- ==================================================================
-- SQL SCRIPT TO CORRECT FABRIC PRICES FOR SUPPLIERS: KARAMS AND KOYO
-- ==================================================================

BEGIN;

-- 1. Create a temporary table to hold the correct prices
CREATE TEMP TABLE temp_precos_corretos (
    fornecedor_id bigint,
    categoria_nome varchar,
    marca_nome varchar,
    descricao varchar,
    largura numeric,
    profundidade numeric,
    altura numeric,
    tecido_nome varchar,
    novo_valor numeric
);

-- 2. Populate the temporary table















-- 3. Update the production active prices by matching the module and fabric
UPDATE pi.modulo_tecido mt
SET valor_tecido = tmp.novo_valor
FROM temp_precos_corretos tmp
JOIN pi.modulo m ON m.id_fornecedor = tmp.fornecedor_id
    AND UPPER(m.descricao) = UPPER(tmp.descricao)
    AND ABS(m.largura - tmp.largura) < 0.01
    AND ABS(m.profundidade - tmp.profundidade) < 0.01
    AND ABS(m.altura - tmp.altura) < 0.01
JOIN pi.marca mc ON m.id_marca = mc.id AND UPPER(mc.nome) = UPPER(tmp.marca_nome)
JOIN pi.categoria cat ON m.id_categoria = cat.id AND UPPER(cat.nome) = UPPER(tmp.categoria_nome)
JOIN pi.tecido t ON UPPER(t.nome) = UPPER(tmp.tecido_nome)
WHERE mt.id_modulo = m.id
  AND mt.id_tecido = t.id
  AND mt.fl_ativo = true;

-- 4. Clean up
DROP TABLE temp_precos_corretos;

COMMIT;
